//! Ingests pager decoder output from stdin and emits readable monitor artifacts.
//!
//! Expected input is line-oriented output from decoders such as multimon-ng
//! POCSAG/FLEX. The collector keeps the raw decoder line in append-only logs
//! and writes the newest readable message as a Semantic PleromaticFrame.

use distributed_inference::pleromatic_frame::{PleromaticFrame, PleromaticMediaType};
use serde_json::json;
use std::io::{self, BufRead, Write};
use std::time::{SystemTime, UNIX_EPOCH};

fn main() {
    let stdin = io::stdin();
    for line in stdin.lock().lines() {
        let line = match line {
            Ok(line) => line,
            Err(_) => continue,
        };

        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }

        let message = normalize_decoder_line(trimmed);
        if message.is_empty() {
            continue;
        }

        let now_ms = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .map(|d| d.as_millis() as u64)
            .unwrap_or(0);

        let semantic = format!("PAGER {}", message);
        let mut frame = PleromaticFrame::grounding(
            "pager_gateway".to_string(),
            PleromaticMediaType::Semantic,
            semantic.as_bytes().to_vec(),
        );
        frame
            .attributes
            .insert("rf_protocol".to_string(), "pocsag_flex".to_string());
        frame
            .attributes
            .insert("decoder_line".to_string(), trimmed.to_string());

        match bincode::serialize(&frame) {
            Ok(bytes) => {
                if let Err(err) = std::fs::write("pager_residue.frame", bytes) {
                    eprintln!("[PAGER] failed to write pager_residue.frame: {}", err);
                }
            }
            Err(err) => eprintln!("[PAGER] failed to encode pager frame: {}", err),
        }

        append_jsonl(now_ms, trimmed, &message);
        append_markdown(now_ms, &message);
        log_gateway(&semantic);
    }
}

fn normalize_decoder_line(line: &str) -> String {
    let mut text = line.trim().to_string();

    for marker in ["Alpha:", "Numeric:", "TEXT:", "ALN:", "NUM:"] {
        if let Some((_, rest)) = text.split_once(marker) {
            text = rest.trim().to_string();
            break;
        }
    }

    text.chars()
        .map(|ch| if ch.is_control() { ' ' } else { ch })
        .collect::<String>()
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ")
}

fn append_jsonl(timestamp_ms: u64, decoder_line: &str, message: &str) {
    let record = json!({
        "time_ms": timestamp_ms,
        "protocol": "pocsag_flex",
        "decoder": "multimon-ng",
        "message": message,
        "raw": decoder_line
    });

    match std::fs::OpenOptions::new()
        .append(true)
        .create(true)
        .open("pager_messages.jsonl")
    {
        Ok(mut f) => {
            if let Err(err) = writeln!(f, "{}", record) {
                eprintln!("[PAGER] failed to append pager_messages.jsonl: {}", err);
            }
        }
        Err(err) => eprintln!("[PAGER] failed to open pager_messages.jsonl: {}", err),
    }
}

fn append_markdown(timestamp_ms: u64, message: &str) {
    let exists = std::path::Path::new("pager_messages.md").exists();
    match std::fs::OpenOptions::new()
        .append(true)
        .create(true)
        .open("pager_messages.md")
    {
        Ok(mut f) => {
            if !exists {
                let _ = writeln!(f, "| Time ms | Message |\n|---:|---|");
            }
            let escaped = message.replace('|', "\\|");
            if let Err(err) = writeln!(f, "| {} | {} |", timestamp_ms, escaped) {
                eprintln!("[PAGER] failed to append pager_messages.md: {}", err);
            }
        }
        Err(err) => eprintln!("[PAGER] failed to open pager_messages.md: {}", err),
    }
}

fn log_gateway(message: &str) {
    let log_msg = format!("[PAGER] RESOLVED: {}", message);
    let _ = std::fs::OpenOptions::new()
        .append(true)
        .create(true)
        .open("gateway.log")
        .and_then(|mut f| writeln!(f, "{}", log_msg));
    eprintln!("\x1b[38;5;51m{}\x1b[0m", log_msg);
}
